export type BlockType = 'TITLE' | 'LIST' | 'IMAGE' | 'SPACER' | 'PARAGRAPH' | 'CARD' | 'BADGE' | 'BOX' | 'USER';

export interface Block {
  type: BlockType;
  content?: string | string[];
  options?: {
    highlight?: string;
    variant?: 'default' | 'accent' | 'muted' | 'box' | 'ghost' | 'outlined' | 'pill' | 'oval' | 'check-list' | 'twitter-post';
    size?: 'sm' | 'md' | 'lg';
    icon?: string;
    customIcon?: string; // URL da imagem ou string SVG
    align?: 'left' | 'center' | 'right';
    // Text styling overrides
    fontSize?: number;
    color?: string;
    letterSpacing?: number;
    lineHeight?: number;
    textAlign?: 'left' | 'center' | 'right';
    fontFamily?: 'sans' | 'serif';
    handle?: string; // For USER block
    avatar?: string; // For USER block
    hideName?: boolean; // For USER block
  };
}

export interface Project {
  id: string;
  name: string;
  client_name: string; // Adicionado para suporte ao Supabase
  updatedAt: number;
  data: string; // JSON string do carrossel
  slideCount: number;
}

export type LayoutType = 'CENTERED' | 'STACKED' | 'SPLIT_IMAGE_TOP' | 'SPLIT_IMAGE_SIDE' | 'EDITORIAL' | 'GRID';

export interface TemplateDefinition {
  name: string;
  description: string;
  layoutType: LayoutType;
  allowedBlocks: BlockType[];
  maxBlocks?: number;
}

export interface SlideImageConfig {
  type: 'IMAGE_SELECT' | 'IMAGE_BACKGROUND' | 'IMAGE_BOX' | 'FOCUS_SUBJECT' | 'IMAGE_GLASS_CARD' | 'IMAGE_SPLIT_HALF' | 'NONE';
  url?: string;
  overlay?: 'dark' | 'blur-card' | 'none';
  boxOverlay?: 'dark' | 'light';
  // Fix: Expanded position type to support vertical layouts
  position?: 'right' | 'left' | 'top' | 'bottom';
  format?: 'png' | 'jpg';
  scale?: number;
  x?: number;
  y?: number;
  width?: number;
  backgroundOpacity?: number; // Nova propriedade para opacidade do fundo
  // Visual Styles
  borderWidth?: number;
  borderColor?: string;
  hasShadow?: boolean;
  hasTornEdges?: boolean; // Effect for paper-like look
}

export interface SlideDefinition {
  template: string;
  image?: SlideImageConfig;
  options?: {
    theme?: 'dark' | 'light';
    background?: string;
    accent?: string;
    text?: string;
    cardBg?: string; // Nova propriedade para cor dos boxes
    cardTextColor?: string; // Nova propriedade para cor do texto dos boxes/cards
    cardOpacity?: number; // Nova propriedade para opacidade dos boxes/cards
    hlBgColor?: string; // Cor de fundo do highlight [[...]]
    hlTextColor?: string; // Cor do texto do highlight [[...]]
    blockGap?: number; // Override manual de espaço entre blocos
    sectionGap?: number; // Override manual de espaço entre seções
    padding?: number; // Override manual de padding global
    backgroundImage?: string;
    texture?: {
      type: 'grain' | 'paper' | 'dust' | 'none';
      amount: number;
      blendMode?: string;
    };
    // Novos efeitos globais de pós-produção
    postFX?: {
      noiseAmount?: number;
      noiseMode?: string;
      lightingIntensity?: number;
      clarity?: number;
      vignette?: number;
    };
  };
  blocks: Block[];
}

export interface CarouselDefinition {
  slides: SlideDefinition[];
}

export interface Theme {
  name: string;
  typography: {
    fontFamily: string;
    hero: string;
    title: string;
    paragraph: string;
    body: string;
    small: string;
    titleWeight: string | number;
    letterSpacingTitle: string;
  };
  colors: {
    background: string;
    textPrimary: string;
    textSecondary: string;
    accent: string;
    muted: string;
    highlight: string;
    cardBg?: string; 
    cardTextColor?: string;
    cardOpacity?: number;
    hlBgColor?: string;
    hlTextColor?: string;
  };
  spacing: {
    canvasPadding: string;
    blockGap: string;
    sectionGap: string;
  };
  backgrounds: Record<string, any>;
}

