                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Nome do Projeto</label>
                  <input type="text" value={saveFormData.name} onChange={(e) => setSaveFormData({ ...saveFormData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Ex: Campanha Verão" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Cliente</label>
                  <input type="text" list="client-datalist" value={saveFormData.client} onChange={(e) => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Ex: Impact" />
