      {view === 'DASHBOARD' ? (
        <div className="min-h-screen w-full bg-[#050507] text-white flex flex-col overflow-y-auto custom-scrollbar">
          <header className="px-10 py-8 flex items-center justify-between border-b border-white/5 sticky top-0 bg-[#050507]/80 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4">
              <img src={LOGO_URL} className="h-10 object-contain" alt="Logo" />
              <div className="flex items-center gap-2 px-3 py-1 bg-zinc-800 rounded-lg text-[9px] font-black uppercase text-zinc-500">
                <DatabaseZap size={10} className="text-brand" /> Supabase Sync
              </div>
            </div>
            <div className="flex-1 max-w-xl mx-20 relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={18} />
              <input type="text" placeholder="Pesquisar projetos..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 text-[13px] font-bold text-white outline-none focus:border-brand/50 transition-all" />
            </div>
            <div className="flex gap-4">
              <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 px-6 py-3 bg-white/5 border border-white/10 text-white font-black uppercase text-[11px] rounded-xl hover:bg-white/10 transition-all shadow-xl active:scale-95">
                <Upload size={16} /> Subir Projeto
              </button>
              <button onClick={handleNewProject} className="flex items-center gap-2 px-6 py-3 bg-brand text-black font-black uppercase text-[11px] rounded-xl hover:bg-brand/80 transition-all shadow-xl shadow-brand/10 active:scale-95"><Plus size={16} strokeWidth={3} /> Criar Projeto</button>
            </div>
          </header>
          <main className="p-10 max-w-[1400px] mx-auto w-full">
            <div className="mb-12 flex flex-col gap-6">
                <div className="flex items-center gap-3 text-zinc-400 mb-2">
                  <Filter size={18} className="text-brand" />
                  <h2 className="text-[10px] font-black uppercase tracking-[0.2em]">Clientes</h2>
