                          <div className="flex gap-4"><TransformControl label="Offset X" value={imageConfig.x ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'x'], v)} /><TransformControl label="Offset Y" value={imageConfig.y ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'y'], v)} /></div>
                          <TransformControl label="Opacidade do Fundo" value={imageConfig.backgroundOpacity ?? 1} min={0} max={1} step={0.05} onChange={(v) => updateSlideProperty(['image', 'backgroundOpacity'], v)} />
