          <div className="relative z-10 h-full w-full flex flex-col justify-center items-start" style={{ padding: canvasPadding }}>
            <div className={`w-full max-w-[840px] mx-auto flex flex-col justify-center min-h-0 ${isSocialPost ? 'border border-white/10 rounded-[40px] p-16 bg-white/5' : ''}`}>
              {renderBlocks()}
            </div>
          </div>
        </div>
      );
    }
    return (<div style={{ filter: contentFilter }} className="h-full w-full">{renderLayoutInternal()}</div>);
  }

  return (
    <div ref={canvasRef} style={{ backgroundColor: theme.colors.background, color: theme.colors.textPrimary, fontFamily: theme.typography.fontFamily }} className="relative w-[1080px] h-[1350px] flex flex-col shadow-2xl overflow-hidden shrink-0 select-auto cursor-text">
      {renderTornPaperSVG()}
      {renderLayout()}
      {renderTextureOverlay()}
      {renderFXOverlays()}
    </div>
  )
}

