interface ToolbarState {
  x: number;
  y: number;
  blockIndex: number;
  blockType: string;
  options: any;
}

const FloatingTextToolbar = ({ 
  state, 
  onClose, 
  onUpdate 
}: { 
  state: ToolbarState, 
  onClose: () => void, 
  onUpdate: (updates: { path: (string | number)[], value: any }[]) => void 
}) => {
  const [localFontSize, setLocalFontSize] = useState(state.options?.fontSize || 40);
  const [localSpacing, setLocalSpacing] = useState(state.options?.letterSpacing || 0);
  const [localLineHeight, setLocalLineHeight] = useState(state.options?.lineHeight || 1.2);
  const [localColor, setLocalColor] = useState(state.options?.color || '#ffffff');

  const [pos, setPos] = useState({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const toolbarRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setLocalFontSize(state.options?.fontSize || 40);
    setLocalSpacing(state.options?.letterSpacing || 0);
    setLocalLineHeight(state.options?.lineHeight || 1.2);
    setLocalColor(state.options?.color || '#ffffff');
    setPos({ x: state.x - 160, y: Math.max(20, state.y - 450) });
  }, [state]);

  const onMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    dragStart.current = { x: e.clientX - pos.x, y: e.clientY - pos.y };
    e.stopPropagation();
  };

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      setPos({ x: e.clientX - dragStart.current.x, y: e.clientY - dragStart.current.y });
    };
    const onMouseUp = () => setIsDragging(false);
    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [isDragging]);

  const update = (key: string, val: any) => {
    onUpdate([{ path: ['blocks', state.blockIndex, 'options', key], value: val }]);
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (toolbarRef.current && !toolbarRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    const timeout = setTimeout(() => {
      document.addEventListener('mousedown', handleClickOutside);
    }, 100);
    return () => {
      clearTimeout(timeout);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [onClose]);

  return (
    <div 
      ref={toolbarRef}
      className="fixed z-[1000] bg-zinc-900/95 backdrop-blur-xl border border-white/10 rounded-[28px] shadow-2xl p-6 flex flex-col gap-6 w-80 animate-in zoom-in-95 duration-200 floating-toolbar select-none"
      style={{ top: `${pos.y}px`, left: `${pos.x}px` }}
      onClick={(e) => e.stopPropagation()}
    >
      <div 
        className="flex items-center justify-between cursor-move pb-2 border-b border-white/5 -mt-2"
        onMouseDown={onMouseDown}
      >
        <div className="flex items-center gap-2">
           <GripHorizontal size={14} className="text-zinc-600" />
           <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest">{state.blockType} Editor</span>
        </div>
        <button onClick={onClose} className="p-1 hover:bg-white/5 rounded-full text-zinc-500 hover:text-white"><X size={14}/></button>
      </div>

      <div className="grid grid-cols-1 gap-5">
        <div className="flex gap-4 items-end">
          <div className="flex-1 space-y-1">
             <TransformControl label="Font Size" value={localFontSize} min={10} max={400} step={1} onChange={(v) => { setLocalFontSize(v); update('fontSize', v); }} />
          </div>
          <div className="relative w-12 h-12 rounded-xl overflow-hidden border border-white/10 shadow-inner shrink-0">
             <input type="color" value={localColor} onChange={(e) => { setLocalColor(e.target.value); update('color', e.target.value); }} className="absolute inset-[-4px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none" />
          </div>
        </div>

        <div className="flex gap-4">
          <TransformControl label="Letter Spacing" value={localSpacing} min={-20} max={50} step={1} onChange={(v) => { setLocalFontSize(v); update('letterSpacing', v); }} />
          <TransformControl label="Line Height" value={localLineHeight} min={0.5} max={3.0} step={0.05} onChange={(v) => { setLocalLineHeight(v); update('lineHeight', v); }} />
        </div>

        <div className="space-y-1.5">
           <span className="text-[9px] font-bold text-zinc-500 uppercase px-1">Alignment</span>
           <div className="flex bg-black/40 p-1 rounded-xl border border-white/5 gap-1">
              {[
                { id: 'left', icon: AlignLeft },
                { id: 'center', icon: AlignCenter },
                { id: 'right', icon: AlignRight }
              ].map(align => (
                <button 
                  key={align.id} 
                  onClick={() => update('textAlign', align.id)}
                  className={`flex-1 py-2 flex items-center justify-center rounded-lg transition-all ${state.options?.textAlign === align.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500 hover:text-white'}`}
                >
                  <align.icon size={16} />
                </button>
              ))}
           </div>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [view, setView] = useState<'DASHBOARD' | 'EDITOR'>('DASHBOARD');
  const [activeTab, setActiveTab] = useState<'TEMPLATES' | 'BLOCKS' | 'DESIGN' | 'FX' | 'ASSETS' | 'JSON'>('TEMPLATES');

  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedClientFilter, setSelectedClientFilter] = useState<string | null>(null);

  const [dslInput, setDslInput] = useState(INITIAL_DSL);
  const [carousel, setCarousel] = useState<ValidatedCarousel | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [zoom, setZoom] = useState(0.40);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);

  const [activePaletteId, setActivePaletteId] = useState('1');
  const [brandPresets, setBrandPresets] = useState<any[]>(DEFAULT_BRAND_PRESETS);
  const [isCreatingPalette, setIsCreatingPalette] = useState(false);
  const [newPaletteData, setNewPaletteData] = useState({
    name: '',
    colors: ['#0D0D0D', '#FFFFFF', '#EAB308', '#EAB308', '#EAB308']
  });

  const [toolbarState, setToolbarState] = useState<ToolbarState | null>(null);
  const [isDraggingFile, setIsDraggingFile] = useState(false);

  const [showExportModal, setShowExportModal] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [saveFormData, setSaveFormData] = useState({ name: '', client: '' });
  const [selectedSlidesToExport, setSelectedSlidesToExport] = useState<Set<number>>(new Set());

  const [isExporting, setIsExporting] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [exportStatus, setExportStatus] = useState('');

  const [templates] = useState<TemplateDefinition[]>(templateRegistry.getAll());

  // Derived variables to resolve "Cannot find name" errors
  const currentSlide = useMemo(() => carousel?.slides[currentIndex], [carousel, currentIndex]);
  const imageConfig = useMemo(() => currentSlide?.image, [currentSlide]);
  const isLocked = isExporting || isSyncing;

  const [editingIconBlock, setEditingIconBlock] = useState<{ block: Block; index: number } | null>(null);
  const [iconInput, setIconInput] = useState('');

  const canvasRef = useRef<HTMLDivElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  // Show toast for feedback
  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  const updateSlideProperties = useCallback((updates: { path: (string | number)[], value: any }[]) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        if (!parsed.slides[currentIndex]) return prev;

        updates.forEach(({ path, value }) => {
          let target = parsed.slides[currentIndex];
          for (let i = 0; i < path.length - 1; i++) {
            const key = path[i];
            if (!target[key] || typeof target[key] !== 'object') target[key] = {};
            target = target[key];
          }
          target[path[path.length - 1]] = value;
        });

        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, [currentIndex]);

  const updateGlobalFX = useCallback((key: string, value: any) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        parsed.slides.forEach((slide: any) => {
          if (!slide.options) slide.options = {};
          if (!slide.options.postFX) slide.options.postFX = {};
          slide.options.postFX[key] = value;
        });
        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, []);

  const updateSlideProperty = useCallback((path: (string | number)[], value: any) => {
    updateSlideProperties([{ path, value }]);
  }, [updateSlideProperties]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      updateSlideProperty(['image', 'url'], reader.result as string);
    };
    reader.readAsDataURL(file);
  };

  const processProjectFile = useCallback((file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);
        const result = carouselSchema.safeParse(parsed);
        if (result.success) {
          setDslInput(content);
          setCurrentProjectId(null);
          setSaveFormData({ name: `Importado ${new Date().toLocaleDateString()}`, client: 'Importado' });
          setCurrentIndex(0);
          setView('EDITOR');
          showToast("Projeto importado com sucesso!");
        } else {
          showToast("Arquivo JSON inválido.", "error");
        }
      } catch (err) {
        showToast("Falha ao ler o arquivo.", "error");
      }
    };
    reader.readAsText(file);
  }, [setDslInput, setCurrentProjectId, setSaveFormData, setCurrentIndex, setView, showToast]);

  const handleImportProject = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processProjectFile(file);
  };

  const handleGlobalDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleGlobalDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
  };

  const handleGlobalDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
    const file = e.dataTransfer.files?.[0];
    if (file) processProjectFile(file);
  };

  // Paste (CTRL+V) support for images
  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      if (view !== 'EDITOR') return;
      const items = e.clipboardData?.items;
      if (!items) return;
      for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
          const blob = items[i].getAsFile();
          if (!blob) continue;
          const reader = new FileReader();
          reader.onload = (event) => {
            const result = event.target?.result as string;
            if (result) {
              if (editingIconBlock) {
                updateSlideProperties([
                  { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: result },
                  { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }
                ]);
                showToast("Ícone personalizado colado!");
              } else {
                updateSlideProperty(['image', 'url'], result);
                showToast("Imagem do slide atualizada!");
              }
            }
          };
          reader.readAsDataURL(blob);
          e.preventDefault();
          break;
        }
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [view, updateSlideProperty, updateSlideProperties, editingIconBlock, showToast]);

  // Load Data: Palettes from Supabase, Projects from Local Storage
  const loadData = useCallback(async () => {
    setIsSyncing(true);
    try {
      // Local Projects
      const localProjects = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
      setProjects(localProjects);

      // Palettes from Supabase (Table: brand_palettes)
      const { data, error } = await supabase.from('brand_palettes').select('*');
      if (error) throw error;

      setBrandPresets([...DEFAULT_BRAND_PRESETS, ...(data || [])]);
    } catch (err: any) {
      console.error("Load failed", err);
      showToast("Falha ao sincronizar paletas. Usando locais.", "error");
      const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
      setBrandPresets([...DEFAULT_BRAND_PRESETS, ...localPalettes]);
    } finally {
      setIsSyncing(false);
    }
  }, [showToast]);

  useEffect(() => { loadData(); }, [loadData]);

  const currentPalette = brandPresets.find(p => p.id === activePaletteId)?.colors || DEFAULT_BRAND_PRESETS[0].colors;

  const handleRender = useCallback(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) {
        setCarousel(result.data);
        setError(null);
      } else {
        setError(result.error.issues.map(e => `[${e.path.join(' → ')}]: ${e.message}`).join('\n'));
      }
    } catch (e: any) {
      setError(`Sintaxe: ${e.message}`);
    }
  }, [dslInput]);

  useEffect(() => { handleRender(); }, [handleRender]);

  const handleNewProject = () => {
    setDslInput(INITIAL_DSL);
    setCurrentProjectId(null);
    setCurrentIndex(0);
    setSaveFormData({ name: '', client: '' });
    setView('EDITOR');
  };

  const handleOpenProject = (proj: Project) => {
    setDslInput(proj.data);
    setCurrentProjectId(proj.id);
    setSaveFormData({ name: proj.name, client: proj.client_name });
    setCurrentIndex(0);
    setView('EDITOR');
  };

  const saveToLocal = (newProject: any) => {
    const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
    const index = existing.findIndex((p: any) => p.id === newProject.id);
    let updated;
    if (index >= 0) {
      updated = [...existing];
      updated[index] = newProject;
    } else {
      updated = [newProject, ...existing];
    }
    localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(updated));
    setProjects(updated);
  };

  const handleSaveProject = async () => {
    if (!saveFormData.name.trim()) return;
    setIsSyncing(true);
    const now = Date.now();
    const localId = currentProjectId || `proj_${now}`;

    const projectObj: Project = {
      id: localId,
      name: saveFormData.name,
      client_name: saveFormData.client || 'Geral',
      data: dslInput,
      slideCount: carousel?.slides.length || 0,
      updatedAt: now
    };

    try {
      saveToLocal(projectObj);
      setCurrentProjectId(localId);
      setShowSaveModal(false);
      showToast("Projeto salvo localmente!");
    } catch (err: any) {
      console.error("Save failed", err);
      showToast("Falha ao salvar.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDeleteProject = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation(); 

    const confirmed = window.confirm("Excluir projeto permanentemente?");
    if (!confirmed) return;

    setIsSyncing(true);
    try {
      const existing = JSON.parse(localStorage.getItem(STORAGE_KEYS.PROJECTS) || '[]');
      const updated = existing.filter((p: any) => p.id !== id);
      localStorage.setItem(STORAGE_KEYS.PROJECTS, JSON.stringify(updated));
      setProjects(updated);

      if (currentProjectId === id) handleNewProject();
      showToast("Projeto removido.");
    } catch (err: any) {
      console.error("Delete error:", err);
      showToast("Falha ao excluir.", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleCanvasMouseUp = (e: React.MouseEvent) => {
    const selection = window.getSelection();
    if (!selection || selection.isCollapsed) return;
    const range = selection.getRangeAt(0);
    const rect = range.getBoundingClientRect();
    const targetBlock = (e.target as HTMLElement).closest('[data-block-index]');
    if (targetBlock) {
       const bIndex = parseInt(targetBlock.getAttribute('data-block-index') || '0', 10);
       const bType = targetBlock.querySelector('[data-block-type]')?.getAttribute('data-block-type') || 'Block';
       const currentBlock = carousel?.slides?.[currentIndex]?.blocks?.[bIndex];
       if (currentBlock) {
          setToolbarState({
            x: Number(rect.left) + Number(rect.width) / 2,
            y: Number(rect.top),
            blockIndex: bIndex,
            blockType: bType,
            options: currentBlock.options || {}
          });
       }
    }
  };

  const startBatchExport = async () => {
    if (!carousel || !canvasRef.current || isExporting || selectedSlidesToExport.size === 0) return;
    setShowExportModal(false);
    const originalIndex = currentIndex;
    const exportIndices = Array.from(selectedSlidesToExport).sort((a, b) => Number(a) - Number(b));
    const images: { name: string; dataUrl: string }[] = [];
    setIsExporting(true);
    try {
      const total = exportIndices.length;
      for (let i = 0; i < total; i++) {
        const slideIdx = exportIndices[i];
        setExportStatus(`Processando: ${i + 1} de ${total}`);
        setExportProgress(Math.round(((i + 1) / total) * 100));
        setCurrentIndex(slideIdx);
        await new Promise(resolve => setTimeout(resolve, 850));
        const dataUrl = await captureJpeg(canvasRef.current);
        images.push({ name: `slide-${(i + 1).toString().padStart(2, '0')}.jpg`, dataUrl });
      }
      setExportStatus('Finalizando ZIP...');
      await downloadZip(images, `carousel-${Date.now()}.zip`, dslInput);
      setExportStatus('Exportação concluída!');
      setTimeout(() => {
        setIsExporting(false);
        setExportProgress(0);
        setCurrentIndex(originalIndex);
      }, 1500);
    } catch (err) {
      setError('Erro na exportação.');
      setIsExporting(false);
      setCurrentIndex(originalIndex);
    }
  };

  const handleApplyPalettePreset = (preset: any) => {
    setActivePaletteId(preset.id);
    const defaults = preset.defaults || {
      bg: preset.colors[0],
      accent: preset.colors[2],
      text: preset.colors[1],
      cardBg: preset.colors[2]
    };
    updateSlideProperties([
      { path: ['options', 'background'], value: defaults.bg },
      { path: ['options', 'accent'], value: defaults.accent },
      { path: ['options', 'text'], value: defaults.text },
      { path: ['options', 'cardBg'], value: defaults.cardBg }
    ]);
  };

  const handleCreatePalette = async () => {
    if (!newPaletteData.name.trim()) return;
    setIsSyncing(true);
    const newId = crypto.randomUUID();

    const newPreset = {
      id: newId,
      name: newPaletteData.name,
      colors: newPaletteData.colors,
      defaults: {
        bg: newPaletteData.colors[0],
        accent: newPaletteData.colors[2],
        text: newPaletteData.colors[1],
        cardBg: newPaletteData.colors[2]
      }
    };

    try {
      const { error: insertError } = await supabase.from('brand_palettes').insert([newPreset]);
      if (insertError) throw insertError;
      showToast("Paleta sincronizada com sucesso!");
    } catch (err: any) {
      console.error("Supabase sync failed, falling back to local storage", err);
      showToast("Erro ao sincronizar. Salvando localmente.", "error");
      const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
      localStorage.setItem(STORAGE_KEYS.PALETTES, JSON.stringify([...localPalettes, newPreset]));
    } finally {
      setIsCreatingPalette(false);
      setNewPaletteData({ name: '', colors: ['#0D0D0D', '#FFFFFF', '#EAB308', '#EAB308', '#EAB308'] });
      loadData();
      setIsSyncing(false);
    }
  };

  const handleDeletePalette = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (DEFAULT_BRAND_PRESETS.some(d => d.id === id)) return;
    setIsSyncing(true);
    try {
      const { error } = await supabase.from('brand_palettes').delete().eq('id', id);
      if (error) {
        const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
        const filtered = localPalettes.filter((p: any) => p.id !== id);
        localStorage.setItem(STORAGE_KEYS.PALETTES, JSON.stringify(filtered));
      }
      showToast("Paleta removida.");
      loadData();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleTemplateSelect = (tpl: TemplateDefinition) => {
    const updates: { path: (string | number)[], value: any }[] = [
      { path: ['template'], value: tpl.name }
    ];

    switch(tpl.name) {
      case 'SOCIAL_CHECKLIST':
        updates.push({ path: ['options', 'theme'], value: 'dark' });
        updates.push({ path: ['options', 'background'], value: '#0D0D0D' });
        break;
      case 'PREMIUM_GLASS':
      case 'GLASS_OVERLAY':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_GLASS_CARD' });
        updates.push({ path: ['image', 'boxOverlay'], value: 'dark' });
        break;
      case 'SPLIT_EDITORIAL':
      case 'ASPECT_EDITORIAL':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_SPLIT_HALF' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        break;
      case 'PROFILE_FOCUS':
        updates.push({ path: ['image', 'type'], value: 'FOCUS_SUBJECT' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        break;
      case 'FOCUS_OBJECT':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BOX' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        updates.push({ path: ['image', 'width'], value: 600 });
        break;
      case 'CINEMATIC_BG':
      case 'HERO_STATEMENT':
      case 'MEGA_STATEMENT':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BACKGROUND' });
        updates.push({ path: ['image', 'overlay'], value: 'dark' });
        break;
      case 'IMAGE_SIDEBAR':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BOX' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        updates.push({ path: ['image', 'width'], value: 400 });
        break;
      case 'CARD_BOX':
      case 'BENTO_SHOWCASE':
        updates.push({ path: ['image', 'type'], value: 'NONE' });
        break;
      case 'MINIMAL_CHECKLIST':
      case 'INFO_LIST_V1':
      case 'CARD_CLUSTER':
        if (!imageConfig?.url) {
           updates.push({ path: ['image', 'type'], value: 'NONE' });
        }
        break;
    }

    updateSlideProperties(updates);
    showToast(`Template ${tpl.name.replace(/_/g, ' ')} aplicado!`, "success");
  };

  const clients = useMemo(() => {
    const set = new Set(projects.map(p => p.client_name));
    return Array.from(set).sort();
  }, [projects]);

  const filteredProjects = useMemo(() => {
    return projects.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || p.client_name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesClient = selectedClientFilter ? p.client_name === selectedClientFilter : true;
      return matchesSearch && matchesClient;
    });
  }, [projects, searchQuery, selectedClientFilter]);

  const currentUserBlockIndex = useMemo(() => {
    return currentSlide?.blocks.findIndex(b => b.type === 'USER') ?? -1;
  }, [currentSlide]);

  return (
    <div 
      onDragOver={handleGlobalDragOver}
      onDragLeave={handleGlobalDragLeave}
      onDrop={handleGlobalDrop}
      className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden relative"
    >
      {isDraggingFile && (
        <div className="fixed inset-0 z-[10000] bg-brand/10 backdrop-blur-sm border-4 border-dashed border-brand/50 flex items-center justify-center pointer-events-none">
          <div className="bg-zinc-900 p-10 rounded-[40px] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in-95">
             <Upload size={64} className="text-brand animate-bounce" />
             <p className="text-xl font-black text-white uppercase italic tracking-tighter">Solte o projeto para importar</p>
          </div>
        </div>
      )}

      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-[0_30px_90px_rgba(0,0,0,0.6)] backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-brand/95 text-black' : 'bg-red-500/95 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} strokeWidth={3} /> : <AlertCircle size={28} strokeWidth={3} />}
          <span className="text-[16px] font-black uppercase tracking-[0.1em]">{toast.message}</span>
        </div>
      )}

      <input type="file" ref={importInputRef} onChange={handleImportProject} accept=".json" className="hidden" />

      {toolbarState && (
        <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />
      )}

      {showExportModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowExportModal(false)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Exportar Carrossel</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">ZIP conterá imagens + arquivo de configuração do projeto</p>
                 </div>
                 <button onClick={() => setShowExportModal(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500 transition-colors"><X size={24}/></button>
              </div>

