                                   <button onClick={() => { const currentText = block.content as string; updateSlideProperty(['blocks', bIdx, 'content'], `${currentText} **Negrito**`); }} className="flex items-center gap-2 px-3 py-2 bg-white/5 rounded-lg text-[9px] font-black uppercase text-zinc-400 hover:text-white transition-all"><Bold size={12} /> Negrito</button>
