                                    <input type="color" value={block.options?.color || '#ffffff'} onChange={(e) => updateSlideProperty(['blocks', bIdx, 'options', 'color'], e.target.value)} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                                    <div className="w-5 h-5 rounded-full border border-white/20" style={{ backgroundColor: block.options?.color || '#ffffff' }} />
                                    <span className="ml-3 text-[10px] font-mono text-zinc-500 group-hover/color:text-zinc-300">{block.options?.color || '#ffffff'}</span>
                                  </div>
                                </div>
                                <div className="space-y-1.5">
                                  <span className="text-[9px] font-bold text-zinc-500 uppercase px-1">Variante</span>
                                  <select value={block.options?.variant || 'default'} onChange={(e) => updateSlideProperty(['blocks', bIdx, 'options', 'variant'], e.target.value)} className="w-full h-10 bg-black/40 border border-white/5 rounded-xl px-3 text-[10px] font-black uppercase text-zinc-400 outline-none focus:border-brand/50">
                                    <option value="default">Default</option><option value="accent">Acento</option><option value="muted">Muted</option><option value="box">Box</option><option value="ghost">Ghost</option><option value="outlined">Outlined</option><option value="pill">Pill</option><option value="oval">Oval</option><option value="twitter-post">Twitter Post</option>
                                  </select>
                                </div>
                              </div>
                           </div>
                        </div>
                      </div>
                    ))}
                    <button onClick={() => { const nextBlocks = [...(carousel?.slides[currentIndex]?.blocks || []), { type: 'PARAGRAPH', content: 'Novo parágrafo de conteúdo...', options: { fontSize: 32 } }]; updateSlideProperty(['blocks'], nextBlocks); showToast("Bloco adicionado."); }} className="w-full py-6 border-2 border-dashed border-white/5 rounded-[32px] flex flex-col items-center justify-center gap-3 text-zinc-600 hover:border-brand/20 hover:text-brand hover:bg-brand/5 transition-all group">
                       <PlusCircle size={24} className="group-hover:scale-110 transition-transform" /><span className="text-[10px] font-black uppercase tracking-widest">Novo Bloco de Texto</span>
                    </button>
                  </div>
                </div>
              ) : activeTab === 'DESIGN' ? (
                <div className="space-y-10 animate-in fade-in slide-in-from-left-4 duration-300">
                  <section className="space-y-4">
                    <div className="flex items-center justify-between px-1">
                      <div className="flex items-center gap-2"><h3 className="text-[10px] font-black text-brand uppercase tracking-widest">Brand Palettes</h3><span title="Sincronizado via Supabase"><DatabaseZap size={10} className="text-brand" /></span></div>
                      <button onClick={() => setIsCreatingPalette(true)} className="text-[8px] font-black text-brand uppercase flex items-center gap-1 hover:text-white transition-all bg-brand/10 px-2.5 py-1.5 rounded-lg border border-brand/20"><Plus size={10} strokeWidth={3} /> New Palette</button>
