import React, { useMemo } from 'react'
import { ValidatedSlide } from '../template-dsl/schema'
import { TOKENS } from '../design-tokens/tokens'
import { renderBlock } from './renderBlock'
import { templateRegistry } from '../domain/templates/TemplateRegistry'
import { Image as ImageIcon, Box, User, Layers, Package } from 'lucide-react'
import { Block } from '../types'

export const SlideCanvas: React.FC<{ 
  slide: ValidatedSlide, 
  index: number, 
  canvasRef: React.RefObject<HTMLDivElement>,
  onEditIcon?: (block: Block, index: number) => void 
}> = ({ slide, index, canvasRef, onEditIcon }) => {
  const isLight = slide.options?.theme === 'light'
  const templateDef = templateRegistry.get(slide.template)

  const theme = useMemo(() => {
    const baseBackground = isLight ? '#F2F2F2' : '#0D0D0D'
    const baseTextPrimary = isLight ? '#000000' : '#FFFFFF'
    const baseTextSecondary = isLight ? '#333333' : 'rgba(255, 255, 255, 0.9)'

    return {
      ...TOKENS,
      colors: {
        ...TOKENS.colors,
        background: slide.options?.background || baseBackground,
        textPrimary: slide.options?.text || baseTextPrimary,
        textSecondary: slide.options?.text ? `${slide.options.text}cc` : baseTextSecondary,
        accent: slide.options?.accent || TOKENS.colors.accent,
        highlight: slide.options?.accent || TOKENS.colors.highlight,
        cardBg: slide.options?.cardBg || slide.options?.accent || TOKENS.colors.accent,
        cardTextColor: slide.options?.cardTextColor,
        cardOpacity: slide.options?.cardOpacity !== undefined ? slide.options.cardOpacity : 1,
        hlBgColor: slide.options?.hlBgColor || slide.options?.accent || TOKENS.colors.accent,
        hlTextColor: slide.options?.hlTextColor || '#000000',
      }
    }
  }, [isLight, slide.options?.background, slide.options?.accent, slide.options?.text, slide.options?.cardBg, slide.options?.cardTextColor, slide.options?.cardOpacity, slide.options?.hlBgColor, slide.options?.hlTextColor])

  if (!templateDef) return <div ref={canvasRef} className="w-[1080px] h-[1350px] bg-red-900 flex items-center justify-center text-white font-bold">ERROR: TEMPLATE NOT FOUND</div>

  const imageConfig = slide.image;
  const texture = slide.options?.texture;
  const fx = slide.options?.postFX;

  const blockGap = slide.options?.blockGap !== undefined ? slide.options.blockGap : 16;
  const sectionGap = slide.options?.sectionGap !== undefined ? slide.options.sectionGap : 48;
  const padding = slide.options?.padding !== undefined ? slide.options.padding : 80;

  const renderTornPaperSVG = () => {
    if (!imageConfig?.hasTornEdges) return null;
    const maskId = `tornMask-${index}`;
    return (
      <svg width="0" height="0" className="absolute">
        <defs>
          <clipPath id={maskId} clipPathUnits="objectBoundingBox">
            <path d="M0.04,0.06 C0.1,0.04 0.15,0.08 0.2,0.05 C0.25,0.03 0.3,0.07 0.35,0.04 C0.4,0.02 0.45,0.06 0.5,0.04 C0.55,0.03 0.6,0.07 0.65,0.05 C0.7,0.03 0.75,0.06 0.8,0.04 C0.85,0.03 0.9,0.07 0.96,0.05 C0.98,0.1 0.95,0.15 0.97,0.2 C0.99,0.25 0.96,0.3 0.98,0.35 C1.0,0.4 0.97,0.45 0.99,0.5 C1.0,0.55 0.96,0.6 0.98,0.65 C1.0,0.7 0.97,0.75 0.99,0.8 C1.0,0.85 0.96,0.9 0.94,0.96 C0.9,0.98 0.85,0.95 0.8,0.97 C0.75,0.99 0.7,0.96 0.65,0.98 C0.6,1.0 0.55,0.97 0.5,0.99 C0.45,1.0 0.4,0.96 0.35,0.98 C0.3,1.0 0.25,0.97 0.2,0.99 C0.15,1.0 0.1,0.96 0.04,0.94 C0.02,0.9 0.05,0.85 0.03,0.8 C0.01,0.75 0.04,0.7 0.02,0.65 C0.0,0.6 0.03,0.55 0.01,0.5 C0.0,0.45 0.04,0.4 0.02,0.35 C0.0,0.3 0.03,0.25 0.01,0.2 C0.0,0.15 0.04,0.1 0.04,0.06 Z" />
          </clipPath>
        </defs>
      </svg>
    );
  };

  const renderImage = (className: string, fit: 'cover' | 'contain' = 'cover') => {
    if (!imageConfig?.url) return null;
    const imgScale = imageConfig.imageScale ?? 1;
    const imgRotation = imageConfig.imageRotation ?? 0;
    const imgX = imageConfig.imageX ?? 0;
    const imgY = imageConfig.imageY ?? 0;
    const maskId = `tornMask-${index}`;

    return (
      <div className={`${className} transition-all duration-300 ease-out`} style={{ clipPath: imageConfig.hasTornEdges ? `url(#${maskId})` : 'none' }}>
        <img 
          src={imageConfig.url} 
          className={`w-full h-full ${fit === 'cover' ? 'object-cover' : 'object-contain'}`} 
          style={{ 
            objectPosition: `calc(50% + ${imgX}px) calc(50% + ${imgY}px)`, 
            transform: `scale(${imgScale}) rotate(${imgRotation}deg)`, 
            opacity: imageConfig.backgroundOpacity ?? 1 
          }} 
          alt="" 
        />
      </div>
    );
  };

  const renderBlocks = () => (
    <div className="w-full relative z-30 flex flex-col" style={{ gap: `${blockGap}px` }}>
      {slide.blocks.map((b, i) => <React.Fragment key={i}>{renderBlock(b, theme, onEditIcon, false, 0, i)}</React.Fragment>)}
    </div>
  );

  const renderLayout = () => {
    const canvasPadding = `${padding}px`;
    const boxWidth = imageConfig?.width || 480;

    const imageBoxStyle: React.CSSProperties = {
      border: imageConfig?.borderWidth ? `${imageConfig.borderWidth}px solid ${imageConfig.borderColor || '#FFFFFF'}` : 'none',
      boxShadow: imageConfig?.hasShadow ? `0 40px 100px -20px rgba(0,0,0,0.6)` : 'none',
      transform: `translate(${imageConfig?.boxX ?? 0}px, ${imageConfig?.boxY ?? 0}px) scale(${imageConfig?.boxScale ?? 1}) rotate(${imageConfig?.boxRotation ?? 0}deg)`,
      width: `${boxWidth}px`,
      flexShrink: 0
    };

    const renderLayoutInternal = () => {
      // Novo motor modular IMAGE_BOX
      if (imageConfig?.type === 'IMAGE_BOX') {
          const isRight = (imageConfig.position || 'right') === 'right';
          return (
            <div className={`relative h-full w-full flex items-center ${isRight ? 'flex-row' : 'flex-row-reverse'}`} style={{ padding: canvasPadding, gap: `${sectionGap}px` }}>
              <div className="flex-1 min-w-0 z-20">
                {renderBlocks()}
              </div>
              <div style={imageBoxStyle} className={`h-[850px] relative transition-all duration-300 z-10 bg-zinc-800 rounded-[50px] overflow-hidden border-4 border-white/10`}>
                {imageConfig.url ? (renderImage("w-full h-full", "cover")) : (<div className="flex flex-col items-center justify-center h-full opacity-10"><Box size={100} /><p className="font-black uppercase text-xs">Image Slot</p></div>)}
              </div>
            </div>
          );
      }

      // Estilo Glass / Overlay
      if (imageConfig?.type === 'IMAGE_GLASS_CARD' || templateDef.name === 'GLASS_OVERLAY') {
        return (
          <div className="relative h-full w-full">
            <div className="absolute inset-0 overflow-hidden z-0 bg-zinc-900">{renderImage("w-full h-full", "cover")}</div>
            <div className="relative z-10 h-full w-full flex flex-col justify-center items-center" style={{ padding: canvasPadding }}>
              <div style={{ ...imageBoxStyle, width: '100%', maxWidth: '840px' }} className={`backdrop-blur-[20px] p-20 rounded-[80px] border border-white/30 bg-black/60`}>
                {renderBlocks()}
              </div>
            </div>
          </div>
        );
      }

      // Estilo Editorial Split
      if (imageConfig?.type === 'IMAGE_SPLIT_HALF' || templateDef.name === 'ASPECT_EDITORIAL') {
        const isRight = (imageConfig?.position || 'right') === 'right';
        return (
          <div className={`relative h-full w-full flex ${isRight ? 'flex-row' : 'flex-row-reverse'}`} style={{ backgroundColor: theme.colors.background }}>
            <div className="flex-1 h-full flex flex-col justify-center px-24 z-20 min-w-0">{renderBlocks()}</div>
            <div style={imageBoxStyle} className="h-full relative overflow-hidden bg-zinc-900 border-x border-white/5 z-10">{renderImage("w-full h-full", "cover")}</div>
          </div>
        );
      }

      // Default (SOCIAL_CHECKLIST e outros)
      return (
        <div className="relative h-full w-full">
          {imageConfig?.type === 'IMAGE_BACKGROUND' && (
            <div className="absolute inset-0 overflow-hidden z-0 w-full">
              {renderImage("w-full h-full", "cover")}
              {imageConfig?.overlay === 'dark' && <div className="absolute inset-0 bg-black/60" />}
            </div>
          )}
          <div className="relative z-10 h-full w-full flex flex-col justify-center items-start" style={{ padding: canvasPadding }}>
            <div className={`w-full max-w-[840px] mx-auto flex flex-col justify-center min-h-0 ${templateDef.name === 'SOCIAL_CHECKLIST' ? 'border border-white/10 rounded-[40px] p-16 bg-white/5' : ''}`}>
              {renderBlocks()}
            </div>
          </div>
        </div>
      );
    }

    return (<div className="h-full w-full">{renderLayoutInternal()}</div>);
  }

  return (
    <div ref={canvasRef} style={{ backgroundColor: theme.colors.background, color: theme.colors.textPrimary, fontFamily: theme.typography.fontFamily }} className="relative w-[1080px] h-[1350px] flex flex-col shadow-2xl overflow-hidden shrink-0 select-auto">
      {renderTornPaperSVG()}
      {renderLayout()}
      {/* Texture e FX omitidos para brevidade mas devem ser mantidos se o componente total for substituido */}
    </div>
  )
}
